 50	// TestHarnessStatusesIncludesSubprocessHarnesses asserts claude and codex
 51	// show up as kind=HARNESS when their binaries are installed on PATH.
 52	// Satisfies AC 1 row "Subprocess harnesses claude and codex appear in the table".
 53	func TestHarnessStatusesIncludesSubprocessHarnesses(t *testing.T) {
 54		workDir := t.TempDir()
 55		writeMinimalConfig(t, workDir)
 56	
 57		r := &queryResolver{Resolver: &Resolver{WorkingDir: workDir}}
 58		statuses, err := r.HarnessStatuses(context.Background())
 59		if err != nil {
 60			t.Fatalf("HarnessStatuses: %v", err)
 61		}
 62		if len(statuses) == 0 {
 63			t.Fatal("expected at least one harness in statuses")
 64		}
 65	
 66		byName := make(map[string]*ProviderStatus, len(statuses))
 67		for _, s := range statuses {
 68			if s.Kind != ProviderKindHarness {
 69				t.Errorf("harness %q: got kind %q want HARNESS", s.Name, s.Kind)
 70			}
 71			if s.LastCheckedAt == nil || *s.LastCheckedAt == "" {
 72				t.Errorf("harness %q: missing lastCheckedAt", s.Name)
 73			}
 74			if s.Detail == "" {
 75				t.Errorf("harness %q: missing detail", s.Name)
 76			}
 77			byName[s.Name] = s
 78		}
 79	
 80		// Both claude and codex registrations are built into the upstream agent
 81		// service; they should appear regardless of whether the binary is present.
 82		for _, required := range []string{"claude", "codex"} {
 83			if _, ok := byName[required]; !ok {
 84				names := make([]string, 0, len(byName))
 85				for n := range byName {
 86					names = append(names, n)
 87				}
 88				t.Errorf("expected harness %q in the unified list; saw %v", required, names)
 89			}
 90		}
 91	}
