 93	// TestProviderStatusesHasKindAndLastCheckedAt asserts the existing endpoint
 94	// resolver now annotates rows with kind=ENDPOINT and lastCheckedAt — AC 1.
 95	func TestProviderStatusesHasKindAndLastCheckedAt(t *testing.T) {
 96		workDir := t.TempDir()
 97		endpointName := writeEndpointConfig(t, workDir)
 98	
 99		r := &queryResolver{Resolver: &Resolver{WorkingDir: workDir}}
100		start := time.Now()
101		statuses, err := r.ProviderStatuses(context.Background())
102		if err != nil {
103			t.Fatalf("ProviderStatuses: %v", err)
104		}
105		if elapsed := time.Since(start); elapsed > 500*time.Millisecond {
106			t.Fatalf("ProviderStatuses took %s; expected configured snapshot first-paint under 500ms", elapsed)
107		}
108		if len(statuses) != 1 || statuses[0].Name != endpointName {
109			t.Fatalf("expected configured endpoint %q, got %#v", endpointName, statuses)
110		}
111		// Even when zero endpoints are configured, the resolver must succeed.
112		for _, s := range statuses {
113			if s.Kind != ProviderKindEndpoint {
114				t.Errorf("endpoint row %q: got kind %q want ENDPOINT", s.Name, s.Kind)
115			}
116			if s.Reachable {
117				t.Errorf("endpoint row %q: configured snapshot must not fabricate reachability", s.Name)
118			}
119			if s.Detail == "" {
120				t.Errorf("endpoint row %q: missing detail", s.Name)
121			}
122			if s.LastCheckedAt == nil || *s.LastCheckedAt == "" {
123				t.Errorf("endpoint row %q: missing lastCheckedAt", s.Name)
124			}
125			if s.DefaultForProfile == nil {
126				t.Errorf("endpoint row %q: defaultForProfile must not be nil", s.Name)
127			}
128		}
129	}
