191	// TestProviderTrendReturnsSeries seeds 7 days of usage and checks the trend
192	// resolver returns hourly buckets. AC 3.
193	func TestProviderTrendReturnsSeries(t *testing.T) {
194		workDir := t.TempDir()
195		writeMinimalConfig(t, workDir)
196	
197		now := time.Now().UTC()
198		// Seed one session per hour for the last 7 days on harness=claude.
199		for i := 0; i < 24*7; i++ {
200			t0 := now.Add(-time.Duration(i) * time.Hour)
201			appendSessionForTest(t, workDir, agent.SessionIndexEntry{
202				ID: fmt.Sprintf("t%d", i), Harness: "claude", Provider: "anthropic",
203				StartedAt: t0, Tokens: 100, Outcome: "success",
204			}, t0)
205		}
