212			t.Fatal("expected trend object, got nil")
213		}
214		if trend.Kind != ProviderKindHarness {
215			t.Errorf("kind: got %q want HARNESS", trend.Kind)
216		}
217		// 7 days * 24 hours = 168 buckets.
218		if len(trend.Series) != 168 {
219			t.Errorf("series length: got %d want 168", len(trend.Series))
